__kernel void solver_2(
    int workload,
    int xmax,
    __global fp* x,
    __global fp* y,
    __global fp* params,
    __global fp* com,
    __global fp* err,
    __global fp* scale,
    __global fp* yy,
    __global fp* initvalu_temp,
    __global fp* finavalu_temp) {

    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int tid = bx * NUMBER_THREADS + tx;

    if (tid >= workload) return;

    fp err_exponent = 1.0f / 7.0f;
    fp h_init = 1.0f;
    fp h = h_init;
    int xmin = 0;
    fp tolerance = 10.0f / (fp)(xmax - xmin);

    long y_base = tid * (xmax + 1) * EQUATIONS;
    long y_prev_offset, y_curr_offset;
    long x_base = tid * (xmax + 1);
    int err_base = tid * EQUATIONS;
    int scale_base = tid * EQUATIONS;
    int yy_base = tid * EQUATIONS;
    int params_base = tid * PARAMETERS;
    int init_temp_base = tid * EQUATIONS;
    int finavalu_temp_base = tid * 13 * EQUATIONS;
    int com_base = tid * 3;

    for (int k = 1; k <= xmax; k++) {
        y_prev_offset = y_base + (k - 1) * EQUATIONS;
        y_curr_offset = y_base + k * EQUATIONS;
        long x_curr_offset = x_base + k;

        x[x_curr_offset] = (fp)k;
        h = h_init;

        fp scale_fina = 1.0f;

        for (int j = 0; j < 12; j++) {
            int error_flag = 0;
            int outside = 0;
            fp scale_min = 4.0f;

            // Call embedded_fehlberg_7_8_2 kernel function (device function)
            // embedded_fehlberg_7_8_2(h, x[x_curr_offset], &y[y_prev_offset], &y[y_curr_offset], &params[params_base], &err[err_base], &initvalu_temp[init_temp_base], &finavalu_temp[finavalu_temp_base], &com[com_base]);
            // TODO: implement embedded_fehlberg_7_8_2 and call here

            for (int i = 0; i < EQUATIONS; i++) {
                if (err[err_base + i] > 0) {
                    error_flag = 1;
                }
            }
            if (error_flag != 1) {
                scale_fina = 4.0f;
                break;
            }

            for (int i = 0; i < EQUATIONS; i++) {
                if (y[y_prev_offset + i] == 0.0f) {
                    yy[yy_base + i] = tolerance;
                }
                else {
                    yy[yy_base + i] = fabs(y[y_prev_offset + i]);
                }
                scale[scale_base + i] = 0.8f * pow(tolerance * yy[yy_base + i] / err[err_base + i], err_exponent);
                if (scale[scale_base + i] < scale_min) {
                    scale_min = scale[scale_base + i];
                }
            }
            scale_fina = fmin(fmax(scale_min, 0.125f), 4.0f);

            for (int i = 0; i < EQUATIONS; i++) {
                if (err[err_base + i] > tolerance * yy[yy_base + i]) {
                    outside = 1;
                }
            }
            if (outside == 0) break;

            h = h * scale_fina;

            if (h >= 0.9f) h = 0.9f;

            if (x[x_curr_offset] + h > (fp)xmax) {
                h = (fp)xmax - x[x_curr_offset];
            }
            else if (x[x_curr_offset] + h + 0.5f * h > (fp)xmax) {
                h = 0.5f * h;
            }
        }

        x[x_curr_offset] = x[x_curr_offset] + h;

        if ( /* j */ 12 >= 12) {
            // when the loop ends because of attempts exhausted
            return;
        }
    }
